// Get HTML from response
const raw = $input.first().json;
let html = '';
if (typeof raw.data === 'string') html = raw.data;
else if (typeof raw.body === 'string') html = raw.body;
else if (typeof raw === 'string') html = raw;
else html = JSON.stringify(raw);

const keyword = $node.Webhook.json.body.keyword || '';
const analysis_id = $node.Webhook.json.body.analysis_id || '';
const callback_url = $node.Webhook.json.body.callback_url || '';

const results = [];
const seen = new Set();

function addUrl(url, title) {
  if (!url || !url.startsWith('http')) return;
  if (url.includes('google.') || url.includes('gstatic.') || url.includes('googleusercontent') || url.includes('youtube.com/redirect') || url.includes('/aclk') || url.includes('webcache')) return;
  let domain;
  try { domain = new URL(url).hostname.replace(/^www\./, ''); } catch(e) { return; }
  if (seen.has(domain)) return;
  seen.add(domain);
  results.push({position: results.length + 1, url, title: (title||'').replace(/<[^>]+>/g,'').trim() || domain, domain});
}

// Strategy 1: Google wraps real result URLs in /url?q=ACTUAL_URL&
let m;
const urlQ = /\/url\?q=(https?:\/\/[^&"]+)/g;
while ((m = urlQ.exec(html)) !== null && results.length < 15) {
  addUrl(decodeURIComponent(m[1]), '');
}

// Strategy 2: direct href to external sites
if (results.length < 5) {
  const href = /href="(https?:\/\/[^"]+)"/g;
  while ((m = href.exec(html)) !== null && results.length < 15) {
    addUrl(m[1], '');
  }
}

// Strategy 3: h3 titles (match with results by order)
const titles = [];
const h3 = /<h3[^>]*>([\s\S]*?)<\/h3>/gi;
while ((m = h3.exec(html)) !== null) {
  const t = m[1].replace(/<[^>]+>/g, '').trim();
  if (t) titles.push(t);
}
// Assign titles to results by order
results.forEach((r, i) => { if (titles[i] && r.title === r.domain) r.title = titles[i]; });

// PAA questions
const questions = [];
const paa = /data-q="([^"]+)"/g;
while ((m = paa.exec(html)) !== null && questions.length < 10) questions.push(m[1]);

// Always include debug so we can see what happened
const debug = 'html_len:' + html.length + ' | results:' + results.length + ' | titles:' + titles.length + ' | blocked:' + (html.includes('detected unusual traffic') || html.includes('not a robot') ? 'YES' : 'no') + ' | first300:' + html.substring(0, 300).replace(/\s+/g, ' ');

return [{json: {analysis_id, callback_url, keyword, results, questions, debug}}];

const p = $input.first().json;
const results = p.results || [];
const competitors = results.map(r => ({position: r.position, url: r.url, domain: r.domain, title: r.title, word_count: 0, h1_count: 0, h2_count: 0, h3_count: 0, images: 0, schema_types: '', top_keywords: [], headings: {h1:[],h2:[],h3:[]}}));
return [{json: {
  analysis_id: $node.Webhook.json.body.analysis_id || '',
  callback_url: $node.Webhook.json.body.callback_url || '',
  avg_word_count: 0, avg_headings: 0,
  lsi_keywords: [], content_gap: [],
  questions: p.questions || [],
  competitors: competitors,
  debug: p.debug || ''
}}];
